#!/usr/bin/env python3"""Comprehensive Jira diagnostic script"""import asyncioimport osimport jsonfrom dotenv import load_dotenvfrom autogen_ext.tools.mcp import StdioServerParams, McpWorkbenchload_dotenv()async def diagnose_jira():    """Comprehensive Jira diagnosis."""    def get_required_env(key: str) -> str:        value = os.getenv(key)        if not value:            raise RuntimeError(f"{key} environment variable not found")        return value    jira_server_params = StdioServerParams(        command="uvx",        args=["mcp-atlassian"],        env={            "JIRA_URL": get_required_env("JIRA_URL"),            "JIRA_USERNAME": get_required_env("JIRA_USERNAME"),            "JIRA_API_TOKEN": get_required_env("JIRA_API_TOKEN"),            "TOOLSETS": "all",        },        read_timeout_seconds=60,    )    async with McpWorkbench(jira_server_params) as jira:        print("🔗 Connected to Jira MCP server")        # 1. Check user profile        print("\n1️⃣ Checking user profile...")        try:            profile_result = await jira.call_tool("jira_get_user_profile", {})            if hasattr(profile_result, 'result') and profile_result.result:                content = profile_result.result[0].content                print(f"✅ User Profile: {content[:200]}...")            else:                print(f"✅ Profile Result: {profile_result}")        except Exception as e:            print(f"❌ Error getting profile: {e}")        # 2. List all projects        print("\n2️⃣ Checking available projects...")        try:            projects_result = await jira.call_tool("jira_get_all_projects", {})            if hasattr(projects_result, 'result') and projects_result.result:                content = json.loads(projects_result.result[0].content)                print(f"✅ Found {len(content)} projects:")                for project in content:                    key = project.get('key', 'Unknown')                    name = project.get('name', 'Unknown')                    project_type = project.get('projectTypeKey', 'Unknown')                    print(f"   📁 {key}: {name} ({project_type})")            else:                print(f"✅ Projects Result: {projects_result}")        except Exception as e:            print(f"❌ Error getting projects: {e}")        # 3. Try searching without project filter        print("\n3️⃣ Searching all recent issues...")        try:            recent_result = await jira.call_tool(                "jira_search",                {                    "jql": "ORDER BY created DESC",                    "fields": "summary,project,issuetype",                    "limit": 5                }            )            if hasattr(recent_result, 'result') and recent_result.result:                data = json.loads(recent_result.result[0].content)                total = data.get('total', 0)                issues = data.get('issues', [])                print(f"✅ Found {total} total issues, showing {len(issues)}:")                for issue in issues:                    key = issue.get('key', 'Unknown')                    summary = issue.get('fields', {}).get('summary', 'No summary')                    project_key = issue.get('fields', {}).get('project', {}).get('key', 'Unknown')                    print(f"   🎫 {key} ({project_key}): {summary}")            else:                print(f"✅ Recent Result: {recent_result}")        except Exception as e:            print(f"❌ Error getting recent issues: {e}")        # 4. Check available fields        print("\n4️⃣ Checking available search fields...")        try:            fields_result = await jira.call_tool("jira_search_fields", {})            if hasattr(fields_result, 'result') and fields_result.result:                content = json.loads(fields_result.result[0].content)                print(f"✅ Found {len(content)} searchable fields")                # Show first 10 field names                for field in content[:10]:                    name = field.get('name', 'Unknown')                    field_id = field.get('id', 'Unknown')                    print(f"   🔍 {name} (ID: {field_id})")            else:                print(f"✅ Fields Result: {fields_result}")        except Exception as e:            print(f"❌ Error getting fields: {e}")if __name__ == "__main__":    asyncio.run(diagnose_jira())